import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ArenaJoinQueueComposer implements IMessageComposer<any[]> {
    private _data: any[];

    /**
     * No payload needed – server can infer user + room from session.
     * If you later want to send extra data (e.g. bet amount), add it here.
     */
    constructor() {
        this._data = [];
        console.log('[📤] ArenaJoinQueueComposer sent');
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
